"use client";

import * as React from "react";
import {
  IconAlertTriangle,
  IconArrowsExchange2,
  IconBolt,
  IconRefresh,
  IconStarFilled,
} from "@tabler/icons-react";
import {
  ActionQueue,
  Badge,
  Button,
  Separator,
  type ActionItem,
} from "@gunjo/ui";
import { LineStatusRow } from "./LineStatusRow";
import { LineDetailSheet } from "./LineDetailSheet";
import { statusBadge } from "./status-ui";
import {
  LAST_REFRESHED,
  LINES,
  STATUS_LABEL,
  STATUS_SEVERITY,
  type LineInfo,
} from "./data";

export default function ServiceStatusPage() {
  const [selected, setSelected] = React.useState<LineInfo | null>(null);
  const [sheetOpen, setSheetOpen] = React.useState(false);
  const [autoRefresh, setAutoRefresh] = React.useState(true);

  const openLine = React.useCallback((line: LineInfo) => {
    setSelected(line);
    setSheetOpen(true);
  }, []);

  // Sorted: disruptions first (severity asc), normal last.
  const sortedLines = React.useMemo(
    () =>
      [...LINES].sort(
        (a, b) => STATUS_SEVERITY[a.status] - STATUS_SEVERITY[b.status],
      ),
    [],
  );

  const favorites = React.useMemo(
    () => sortedLines.filter((l) => l.favorite),
    [sortedLines],
  );

  // 重大な運行情報: the serious states (運転見合わせ / 折返し / 直通中止) → ActionQueue triage.
  const serious = React.useMemo(
    () =>
      LINES.filter(
        (l) =>
          l.status === "suspended" ||
          l.status === "turnback" ||
          l.status === "directStop",
      ).sort((a, b) => STATUS_SEVERITY[a.status] - STATUS_SEVERITY[b.status]),
    [],
  );

  const triageItems: ActionItem[] = React.useMemo(
    () =>
      serious.map((l) => {
        const sb = statusBadge(l.status);
        return {
          id: l.id,
          severity: sb.severity,
          kind: STATUS_LABEL[l.status],
          title: l.name,
          detail: (
            <span>
              {l.section && <span className="font-medium">{l.section}</span>}
              {l.cause && <span>（{l.cause}）</span>}
              {l.note ? <span className="block">{l.note}</span> : null}
              <span className="mt-1 flex flex-wrap items-center gap-x-3 gap-y-0.5 text-xs">
                <span>運転再開見込み：{l.resumeEstimate ?? "—"}</span>
                {l.substituteLines && l.substituteLines.length > 0 && (
                  <span className="inline-flex items-center gap-1 text-info">
                    <IconArrowsExchange2 className="size-3.5" aria-hidden />
                    振替輸送あり
                  </span>
                )}
              </span>
            </span>
          ),
          meta: l.occurredAt ? `${l.occurredAt} 発生` : undefined,
          onSelect: () => openLine(l),
        };
      }),
    [serious, openLine],
  );

  const disruptedCount = LINES.filter((l) => l.status !== "normal").length;

  return (
    <div className="mx-auto min-h-dvh w-full max-w-[420px] bg-background pb-10">
      {/* ヘッダー（B2C: アプリのタイトルバー。kit Header は back-office 寄りなので軽量に自作） */}
      <header className="sticky top-0 z-10 border-b bg-background/95 px-4 py-3 backdrop-blur supports-[backdrop-filter]:bg-background/80">
        <div className="flex items-center justify-between">
          <h1 className="text-lg font-bold tracking-tight text-foreground">
            運行情報
          </h1>
          <div className="flex items-center gap-2 text-xs text-muted-foreground">
            <IconRefresh className="size-3.5" aria-hidden />
            <span>{LAST_REFRESHED} 更新</span>
          </div>
        </div>
        <div className="mt-1.5 flex items-center justify-between">
          <p className="text-xs text-muted-foreground">
            首都圏の鉄道
            {disruptedCount > 0 ? (
              <>
                ・<span className="font-semibold text-destructive">{disruptedCount}路線で運行に影響</span>
              </>
            ) : (
              <span className="font-medium text-success">・全線平常運転</span>
            )}
          </p>
          <button
            type="button"
            onClick={() => setAutoRefresh((v) => !v)}
            role="switch"
            aria-checked={autoRefresh}
            className="inline-flex items-center gap-1.5 rounded-full border px-2.5 py-1 text-[11px] text-muted-foreground transition-colors hover:bg-muted focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          >
            <span
              aria-hidden
              className={`size-1.5 rounded-full ${autoRefresh ? "bg-success animate-pulse" : "bg-muted-foreground"}`}
            />
            自動更新 {autoRefresh ? "ON" : "OFF"}
          </button>
        </div>
      </header>

      <main className="space-y-6 px-4 py-4">
        {/* 重大な運行情報（運転見合わせ等） — トリアージ */}
        {triageItems.length > 0 && (
          <section aria-labelledby="serious-heading">
            <div className="mb-2 flex items-center gap-2">
              <IconAlertTriangle className="size-4 text-destructive" aria-hidden />
              <h2 id="serious-heading" className="text-sm font-bold text-foreground">
                重大な運行情報
              </h2>
              <Badge variant="destructive" className="h-5">
                {triageItems.length}
              </Badge>
            </div>
            <ActionQueue
              items={triageItems}
              aria-label="重大な運行情報の一覧"
            />
          </section>
        )}

        {/* マイ路線（お気に入り） */}
        {favorites.length > 0 && (
          <section aria-labelledby="fav-heading">
            <div className="mb-2 flex items-center gap-2">
              <IconStarFilled className="size-4 text-warning" aria-hidden />
              <h2 id="fav-heading" className="text-sm font-bold text-foreground">
                マイ路線
              </h2>
            </div>
            <div className="flex flex-col gap-2">
              {favorites.map((line) => (
                <LineStatusRow key={line.id} line={line} onSelect={openLine} />
              ))}
            </div>
          </section>
        )}

        <Separator />

        {/* 路線別の運行状況一覧（最重要） */}
        <section aria-labelledby="all-heading">
          <div className="mb-2 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <IconBolt className="size-4 text-foreground" aria-hidden />
              <h2 id="all-heading" className="text-sm font-bold text-foreground">
                路線別の運行状況
              </h2>
            </div>
            <span className="text-[11px] text-muted-foreground">
              影響のある路線から表示
            </span>
          </div>
          <div className="flex flex-col gap-2">
            {sortedLines.map((line) => (
              <LineStatusRow key={line.id} line={line} onSelect={openLine} />
            ))}
          </div>
        </section>

        <p className="pt-2 text-center text-[11px] leading-relaxed text-muted-foreground">
          表示は {LAST_REFRESHED} 時点の情報です。
          {autoRefresh ? "約1分ごとに自動更新されます。" : "自動更新はオフです。"}
          <br />
          ご利用の際は各鉄道会社の公式情報もあわせてご確認ください。
        </p>

        <div className="flex justify-center">
          <Button variant="outline" size="lg" className="gap-1.5">
            <IconRefresh className="size-4" aria-hidden />
            今すぐ更新
          </Button>
        </div>
      </main>

      <LineDetailSheet
        line={selected}
        open={sheetOpen}
        onOpenChange={(open) => {
          setSheetOpen(open);
          if (!open) setSelected(null);
        }}
      />
    </div>
  );
}

// 運行情報（運行状況）— realistic sample data for the consumer service-status screen.
// All content is hand-authored Japanese transit vocabulary; no lorem ipsum.

export type ServiceStatus =
  | "normal" // 平常運転
  | "delay" // 遅延
  | "suspended" // 運転見合わせ
  | "directStop" // 直通運転中止
  | "turnback" // 折返し運転
  | "thinned"; // 間引き運転

export type Cause =
  | "人身事故"
  | "信号確認"
  | "信号トラブル"
  | "車両点検"
  | "車両故障"
  | "強風"
  | "大雨"
  | "急病人の救護"
  | "線路内立入";

export interface LineUpdate {
  /** "HH:MM" */
  time: string;
  text: string;
}

export interface LineInfo {
  id: string;
  /** 路線名 */
  name: string;
  /** 運行会社（JR東日本 / 東京メトロ …） */
  operator: string;
  /** 路線カラー（公式ラインカラーに近い値） */
  color: string;
  status: ServiceStatus;
  /** 一覧に出す短い状況メモ（〜の影響で○○方面遅延 など）。平常運転なら null。 */
  note: string | null;
  /** 最終更新 "HH:MM" */
  updatedAt: string;
  favorite?: boolean;

  // --- 詳細（drill-in）---
  /** 影響区間 */
  section?: string;
  cause?: Cause;
  /** 発生時刻 "HH:MM" */
  occurredAt?: string;
  /** 遅延時分（分）。遅延・間引き時に。 */
  delayMinutes?: number;
  /** 運転再開見込み "HH:MM" / 「見込み立たず」 */
  resumeEstimate?: string;
  /** 振替輸送の対象路線名 */
  substituteLines?: string[];
  /** 時系列の更新履歴（新しい順） */
  updates?: LineUpdate[];
}

export const STATUS_LABEL: Record<ServiceStatus, string> = {
  normal: "平常運転",
  delay: "遅延",
  suspended: "運転見合わせ",
  directStop: "直通運転中止",
  turnback: "折返し運転",
  thinned: "間引き運転",
};

/** 重大度の並び順（小さいほど上に出す）。一覧のソートとトリアージに使う。 */
export const STATUS_SEVERITY: Record<ServiceStatus, number> = {
  suspended: 0,
  turnback: 1,
  directStop: 2,
  delay: 3,
  thinned: 4,
  normal: 5,
};

