"use client";

import * as React from "react";
import {
  IconAlertTriangle,
  IconArrowsExchange2,
  IconClockHour4,
  IconFileText,
  IconMapPin,
  IconRefresh,
} from "@tabler/icons-react";
import {
  Badge,
  Button,
  List,
  ListItem,
  MetadataList,
  Separator,
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  TextLink,
  Timeline,
  TimelineDescription,
  TimelineItem,
  TimelineTime,
  TimelineTitle,
} from "@gunjo/ui";
import { LineColorDot, statusBadge } from "./status-ui";
import type { LineInfo } from "./data";
import { STATUS_LABEL } from "./data";

export interface LineDetailSheetProps {
  line: LineInfo | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function LineDetailSheet({ line, open, onOpenChange }: LineDetailSheetProps) {
  // Render guard so the Sheet keeps mounted for exit animation even after `line` clears.
  const [shown, setShown] = React.useState<LineInfo | null>(line);
  React.useEffect(() => {
    if (line) setShown(line);
  }, [line]);

  const l = line ?? shown;
  const badge = l ? statusBadge(l.status) : null;
  const isDisrupted = l ? l.status !== "normal" : false;

  const detailItems = l
    ? [
        l.section
          ? {
              label: "影響区間",
              value: l.section,
              icon: <IconMapPin className="size-4" aria-hidden />,
            }
          : null,
        l.cause
          ? {
              label: "原因",
              value: l.cause,
              icon: <IconAlertTriangle className="size-4" aria-hidden />,
            }
          : null,
        l.occurredAt
          ? {
              label: "発生時刻",
              value: `${l.occurredAt} 頃`,
              icon: <IconClockHour4 className="size-4" aria-hidden />,
            }
          : null,
        typeof l.delayMinutes === "number"
          ? { label: "遅延時分", value: `約${l.delayMinutes}分の遅れ` }
          : null,
        l.resumeEstimate
          ? { label: "運転再開見込み", value: l.resumeEstimate }
          : null,
      ].filter(Boolean as unknown as <T>(v: T | null) => v is T)
    : [];

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent
        side="bottom"
        closeLabel="閉じる"
        className="mx-auto flex max-h-[88vh] w-full max-w-[420px] flex-col gap-0 overflow-y-auto rounded-t-2xl p-0"
      >
        {l && (
          <>
            <SheetHeader className="space-y-0 px-5 pb-4 pt-6 text-left">
              <div className="flex items-center gap-2.5">
                <LineColorDot color={l.color} className="size-5" />
                <SheetTitle className="text-lg">{l.name}</SheetTitle>
              </div>
              <SheetDescription className="mt-1 flex items-center gap-2">
                <span>{l.operator}</span>
                <span aria-hidden>·</span>
                <span>{STATUS_LABEL[l.status]}</span>
              </SheetDescription>
              <div className="mt-3 flex flex-wrap items-center gap-2">
                {badge && (
                  <Badge variant={badge.variant} icon={badge.icon} className="h-6 text-sm">
                    {badge.label}
                  </Badge>
                )}
                <span className="inline-flex items-center gap-1 text-xs text-muted-foreground">
                  <IconRefresh className="size-3.5" aria-hidden />
                  {l.updatedAt} 更新
                </span>
              </div>
              {l.note && (
                <p className="mt-3 text-sm leading-relaxed text-foreground">{l.note}</p>
              )}
            </SheetHeader>

            <Separator />

            {isDisrupted && detailItems.length > 0 && (
              <section className="px-5 py-4" aria-labelledby="detail-status-heading">
                <h3
                  id="detail-status-heading"
                  className="mb-2 text-sm font-semibold text-foreground"
                >
                  現在の状況
                </h3>
                <MetadataList items={detailItems} />
              </section>
            )}

            {l.substituteLines && l.substituteLines.length > 0 && (
              <>
                <Separator />
                <section className="px-5 py-4" aria-labelledby="detail-substitute-heading">
                  <h3
                    id="detail-substitute-heading"
                    className="mb-2 flex items-center gap-1.5 text-sm font-semibold text-foreground"
                  >
                    <IconArrowsExchange2 className="size-4 text-info" aria-hidden />
                    振替輸送のご案内
                  </h3>
                  <p className="mb-2 text-xs text-muted-foreground">
                    以下の路線・経路で振替輸送を実施しています。
                  </p>
                  <List marker="dot" spacing="tight">
                    {l.substituteLines.map((s) => (
                      <ListItem key={s} className="text-foreground">
                        {s}
                      </ListItem>
                    ))}
                  </List>
                </section>
              </>
            )}

            {l.updates && l.updates.length > 0 && (
              <>
                <Separator />
                <section className="px-5 py-4" aria-labelledby="detail-updates-heading">
                  <h3
                    id="detail-updates-heading"
                    className="mb-3 text-sm font-semibold text-foreground"
                  >
                    更新履歴
                  </h3>
                  <Timeline>
                    {l.updates.map((u, i) => (
                      <TimelineItem
                        key={u.time + i}
                        variant={i === 0 ? (isDisrupted ? "warning" : "success") : "muted"}
                        connector={i < l.updates!.length - 1}
                      >
                        <TimelineTime dateTime={u.time}>{u.time}</TimelineTime>
                        <TimelineTitle className="mt-0.5 text-sm font-medium">
                          {i === 0 ? "最新情報" : "経過"}
                        </TimelineTitle>
                        <TimelineDescription className="mt-0.5 leading-relaxed">
                          {u.text}
                        </TimelineDescription>
                      </TimelineItem>
                    ))}
                  </Timeline>
                </section>
              </>
            )}

            <Separator />
            <section className="px-5 py-4">
              <TextLink
                href="#"
                className="inline-flex items-center gap-1.5 text-sm"
                onClick={(e) => e.preventDefault()}
              >
                <IconFileText className="size-4" aria-hidden />
                遅延証明書を表示する
              </TextLink>
            </section>

            <div className="sticky bottom-0 mt-auto border-t bg-background px-5 py-3">
              <Button
                size="xl"
                className="w-full"
                variant="outline"
                onClick={() => onOpenChange(false)}
              >
                閉じる
              </Button>
            </div>
          </>
        )}
      </SheetContent>
    </Sheet>
  );
}

"use client";

import * as React from "react";
import { IconChevronRight, IconRefresh, IconStarFilled } from "@tabler/icons-react";
import { Badge, cn } from "@gunjo/ui";
import { LineColorDot, statusBadge } from "./status-ui";
import type { LineInfo } from "./data";

export interface LineStatusRowProps {
  line: LineInfo;
  onSelect: (line: LineInfo) => void;
}

/**
 * 路線別運行状況の一覧の1行。タップで詳細へ。
 *
 * HAND-ROLLED. The kit has no "status result row / list card" primitive: the
 * by-use-case index points at PersonCell (avatar+name+role — wrong shape, this
 * row has no person) and RouteStops (a numbered停車駅 sequence — wrong model).
 * So this composes @gunjo/ui Badge + a colour dot inside a native <button>.
 */
export function LineStatusRow({ line, onSelect }: LineStatusRowProps) {
  const badge = statusBadge(line.status);
  const isNormal = line.status === "normal";

  // Left accent rail tinted by severity (icon+label already carry meaning; this is reinforcement).
  const accent =
    badge.severity === "critical"
      ? "before:bg-destructive"
      : badge.severity === "warning"
        ? "before:bg-warning"
        : "before:bg-success";

  return (
    <button
      type="button"
      onClick={() => onSelect(line)}
      aria-label={`${line.name} ${badge.label}${line.note ? `。${line.note}` : ""}。詳細を開く`}
      className={cn(
        "relative flex w-full items-center gap-3 overflow-hidden rounded-lg border bg-card px-3.5 py-3 text-left",
        "min-h-[64px] transition-colors hover:bg-muted/60 active:bg-muted",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1",
        "before:absolute before:inset-y-0 before:left-0 before:w-1",
        accent,
        isNormal && "before:opacity-60",
      )}
    >
      <div className="min-w-0 flex-1 pl-1">
        <div className="flex items-center gap-2">
          <LineColorDot color={line.color} className="size-3.5" />
          <span className="truncate text-[15px] font-semibold text-foreground">
            {line.name}
          </span>
          {line.favorite && (
            <IconStarFilled
              className="size-3.5 shrink-0 text-warning"
              aria-label="マイ路線"
            />
          )}
        </div>
        {line.note ? (
          <p className="mt-1 line-clamp-2 text-xs leading-relaxed text-muted-foreground">
            {line.note}
          </p>
        ) : (
          <p className="mt-1 text-xs text-muted-foreground">
            遅れや運休の情報はありません
          </p>
        )}
        <span className="mt-1 inline-flex items-center gap-1 text-[11px] text-muted-foreground">
          <IconRefresh className="size-3" aria-hidden />
          {line.updatedAt} 更新
        </span>
      </div>

      <div className="flex shrink-0 flex-col items-end gap-1.5">
        <Badge variant={badge.variant} icon={badge.icon}>
          {badge.label}
        </Badge>
      </div>
      <IconChevronRight
        className="size-5 shrink-0 text-muted-foreground"
        aria-hidden
      />
    </button>
  );
}

import * as React from "react";
import {
  IconAlertTriangle,
  IconArrowsLeftRight,
  IconBan,
  IconCircleCheck,
  IconClockHour4,
  IconChartBar,
} from "@tabler/icons-react";
import { cn } from "@gunjo/ui";
import type { ActionSeverity } from "@gunjo/ui";
import type { ServiceStatus } from "./data";
import { STATUS_LABEL } from "./data";

type BadgeVariant = "success" | "warning" | "destructive" | "info" | "secondary";

interface StatusBadgeSpec {
  label: string;
  variant: BadgeVariant;
  icon: React.ReactNode;
  /** Maps onto ActionQueue's severity ranking for the triage surface. */
  severity: ActionSeverity;
}

const SIZE = "size-3.5";

/**
 * Single source of truth: each 運行状況 → its Badge variant, icon, label and the
 * ActionQueue severity. Status is never conveyed by colour alone — every state
 * carries an icon + a text label.
 */
export function statusBadge(status: ServiceStatus): StatusBadgeSpec {
  switch (status) {
    case "normal":
      return {
        label: STATUS_LABEL.normal,
        variant: "success",
        icon: <IconCircleCheck className={SIZE} aria-hidden />,
        severity: "neutral",
      };
    case "delay":
      return {
        label: STATUS_LABEL.delay,
        variant: "warning",
        icon: <IconClockHour4 className={SIZE} aria-hidden />,
        severity: "warning",
      };
    case "thinned":
      return {
        label: STATUS_LABEL.thinned,
        variant: "warning",
        icon: <IconChartBar className={SIZE} aria-hidden />,
        severity: "warning",
      };
    case "directStop":
      return {
        label: STATUS_LABEL.directStop,
        variant: "info",
        icon: <IconBan className={SIZE} aria-hidden />,
        severity: "warning",
      };
    case "turnback":
      return {
        label: STATUS_LABEL.turnback,
        variant: "destructive",
        icon: <IconArrowsLeftRight className={SIZE} aria-hidden />,
        severity: "critical",
      };
    case "suspended":
      return {
        label: STATUS_LABEL.suspended,
        variant: "destructive",
        icon: <IconAlertTriangle className={SIZE} aria-hidden />,
        severity: "critical",
      };
  }
}

/** Official-ish line colour swatch. A small custom primitive — the kit has no line-colour token. */
export function LineColorDot({
  color,
  className,
}: {
  color: string;
  className?: string;
}) {
  return (
    <span
      aria-hidden
      className={cn("inline-block size-3 shrink-0 rounded-full", className)}
      style={{ backgroundColor: color }}
    />
  );
}
